1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  enchantment?: number;
8	  cursed?: boolean;
9	}
10	
11	export interface QuoteOptions {
12	  isFollowUp?: boolean;
13	}
14	
15	const PROCESSING_FEE = 5;
16	const FIRST_INSURANCE_RATE = 0.1;
17	const LOYALTY_DISCOUNT = 20;
18	const FOLLOW_UP_DISCOUNT = 15;
19	const LOYALTY_THRESHOLD_YEARS = 2;
20	const HIGH_ENCHANT_THRESHOLD = 5;
21	const HIGH_ENCHANT_SURCHARGE_RATE = 0.3;
22	const CURSE_SURCHARGE_RATE = 0.5;
23	
24	const BASE_PRICES: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	};
30	
31	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
32	const COMPONENT_UNIT_PRICE = 25;
33	const COMPONENT_BLOCK_SIZE = 3;
34	const COMPONENT_BLOCK_PRICE = 60;
35	
36	// Base price for a group of items of the same component type (rune/moonstone).
37	// Exactly 3 of a kind forms a "block" priced at 60; otherwise 25 per item.
38	function componentGroupBase(count: number): number {
39	  return count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PRICE : count * COMPONENT_UNIT_PRICE;
40	}
41	
42	// Sum of base prices for all items, respecting per-type block discounts for components.
43	function policyBaseTotal(items: Item[]): number {
44	  const componentCounts: Record<string, number> = {};
45	  let nonComponentBase = 0;
46	  for (const item of items) {
47	    if (COMPONENT_TYPES.has(item.type)) {
48	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
49	    } else {
50	      nonComponentBase += BASE_PRICES[item.type];
51	    }
52	  }
53	  const componentBase = Object.values(componentCounts).reduce(
54	    (sum, count) => sum + componentGroupBase(count),
55	    0,
56	  );
57	  return nonComponentBase + componentBase;
58	}
59	
60	// Per-item surcharges (curse, high-enchantment) computed as a percentage of
61	// the item's individual base price. Components have no surcharges.
62	function itemSurcharges(item: Item): number {
63	  if (COMPONENT_TYPES.has(item.type)) return 0;
64	  const base = BASE_PRICES[item.type];
65	  let surcharge = 0;
66	  if (item.cursed) surcharge += base * CURSE_SURCHARGE_RATE;
67	  if ((item.enchantment ?? 0) >= HIGH_ENCHANT_THRESHOLD) {
68	    surcharge += base * HIGH_ENCHANT_SURCHARGE_RATE;
69	  }
70	  return surcharge;
71	}
72	
73	export function quote(customer: Customer, items: Item[], options?: QuoteOptions): number {
74	  const baseTotal = policyBaseTotal(items);
75	  const surchargeTotal = items.reduce((sum, item) => sum + itemSurcharges(item), 0);
76	  const firstInsurance = baseTotal * FIRST_INSURANCE_RATE;
77	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? LOYALTY_DISCOUNT : 0;
78	  const followUpDiscount = options?.isFollowUp ? FOLLOW_UP_DISCOUNT : 0;
79	  const premium =
80	    baseTotal + surchargeTotal + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE;
81	  return Math.ceil(premium);
82	}
